          className={`combo-line ${combo >= 3 ? "is-combo-hot" : ""}`}
          aria-live="polite"
        >
          {combo > 1 ? `连击 x${combo}` : "点击木鱼或按空格键"}
        </div>
        <div
          className={`progress-card ${progressPulse ? "is-pulsing" : ""}`}
          aria-label={`距离下一阶段还差 ${Math.max(
            nextMilestone - stats.total,
            0,
          )} 点功德`}
        >
          <div className="progress-copy">
            <span>下一阶段</span>
            <strong>
              {stats.total}/{nextMilestone}
            </strong>
          </div>
          <span className="progress-track">
            <span style={{ width: `${progressPercent}%` }} />
          </span>
        </div>
      </section>

      <section className="growth-panel" aria-label="每日功德签和成就">
        <article className="fortune-card">
          <span className="section-kicker">今日功德签</span>
          <h2>{dailyFortune.title}</h2>
          <p>{dailyFortune.text}</p>
          <div className="fortune-pair">
            <span>宜：{dailyFortune.good}</span>
            <span>忌：{dailyFortune.avoid}</span>
          </div>
          <div className="wish-box">
            <label htmlFor="daily-wish">今日愿望</label>
            <input
              id="daily-wish"
              maxLength={40}
              onChange={(event) => updateWish(event.target.value)}
              placeholder="愿今天不临时拉会"
              type="text"
              value={activeWish}
            />
            <div className="wish-tools">
              <small>愿望仅保存在本机，请勿填写隐私信息。</small>
              <button onClick={rotateWish} type="button">
                换一个
              </button>
            </div>
          </div>
          <button className="share-button" onClick={copyShareText} type="button">
            复制分享文案
          </button>
          <button
            className="share-button share-button-secondary"
            onClick={generateWishCard}
            type="button"
          >
            保存愿望功德图
          </button>
          <small
            className={`share-status ${shareStatus ? "has-feedback" : ""}`}
            aria-live="polite"
          >
            {shareStatus || "分享给需要一点功德的朋友"}
          </small>
          {manualShareText && (
            <label className="manual-share-box">
              <span>手动复制文案</span>
              <textarea readOnly value={manualShareText} />
            </label>
          )}
        </article>

        <article className="achievement-card">
          <div className="achievement-heading">
            <span className="section-kicker">成就</span>
            <strong>{achievementProgress.summary}</strong>
          </div>
          <div className="achievement-progress">
            <p>{achievementProgress.nextLine}</p>
            <span>
              {achievementProgress.nextAchievement
                ? achievementProgress.nextAchievement.condition
                : "可以继续敲一张更好看的分享图"}
            </span>
          </div>
          <div className="badge-grid">
            {achievements.map((item) => (
              <div
                className={`badge-item ${item.unlocked ? "is-unlocked" : ""}`}
                key={item.id}
              >
                <span>{item.unlocked ? "已解锁" : "未解锁"}</span>
                <strong>{item.name}</strong>
                <small>{item.condition}</small>
              </div>
            ))}
          </div>
        </article>

      </section>
    </main>
  );
}

import { normalizeWish } from "./gongde-growth.js";

const cardWidth = 1200;
const cardHeight = 1500;
const fallbackWish = "愿今日心态稳定";

export function createWishCardModel(stats, fortune, wish) {
  const normalizedWish = normalizeWish(wish) || fallbackWish;
  const today = Number(stats?.today) || 0;
  const title = fortune?.title || "今日功德签";
  const avoid = fortune?.avoid ? `，忌${fortune.avoid}` : "";

  return {
    width: cardWidth,
    height: cardHeight,
    wish: normalizedWish,
    countLine: `我已为此敲下 ${today} 点功德`,
    fortuneLine: `今日签：${title}${avoid}`,
    siteLine: "功德敲敲敲 gongdeclicker.com",
  };
}

export function wrapTextForCard(text, maxWidth, measureText) {
  const chars = Array.from(String(text || ""));
  const lines = [];
  let line = "";

  chars.forEach((char) => {
    const next = `${line}${char}`;

    if (line && measureText(next) > maxWidth) {
      lines.push(line);
      line = char;
      return;
    }

    line = next;
  });

  if (line) {
    lines.push(line);
  }

  return lines;
}

export function renderWishCardToDataUrl(stats, fortune, wish, documentRef = document) {
  if (!documentRef?.createElement) {
    throw new Error("Canvas is not available");
  }

  const model = createWishCardModel(stats, fortune, wish);
  const canvas = documentRef.createElement("canvas");
  canvas.width = model.width;
  canvas.height = model.height;

  const context = canvas.getContext("2d");
  if (!context) {
    throw new Error("Canvas context is not available");
  }

  drawCard(context, model);
  return canvas.toDataURL("image/png");
}

function drawCard(context, model) {
  context.fillStyle = "#fff8eb";
  context.fillRect(0, 0, model.width, model.height);

  const gradient = context.createLinearGradient(0, 0, model.width, model.height);
  gradient.addColorStop(0, "rgba(39, 116, 91, 0.18)");
  gradient.addColorStop(0.46, "rgba(255, 248, 235, 0)");
  gradient.addColorStop(1, "rgba(211, 66, 53, 0.14)");
  context.fillStyle = gradient;
  context.fillRect(0, 0, model.width, model.height);

  context.fillStyle = "#fffdf7";
  roundRect(context, 96, 104, 1008, 1292, 34);
  context.fill();

  context.strokeStyle = "#e8d7bd";
  context.lineWidth = 4;
  context.stroke();

  context.fillStyle = "#2f5f98";
  context.font = "800 44px sans-serif";
  context.fillText("今日愿望", 160, 210);

  context.fillStyle = "#211a16";
  context.font = "900 96px sans-serif";
  const wishLines = wrapTextForCard(
    model.wish,
    880,
    (text) => context.measureText(text).width,
  ).slice(0, 3);

  wishLines.forEach((line, index) => {
    context.fillText(line, 160, 365 + index * 122);
  });

  context.fillStyle = "#27745b";
  context.font = "900 58px sans-serif";
  context.fillText(model.countLine, 160, 830);

  context.fillStyle = "#75695f";
  context.font = "700 42px sans-serif";
  wrapTextForCard(
    model.fortuneLine,
    860,
    (text) => context.measureText(text).width,
  )
    .slice(0, 2)
    .forEach((line, index) => {
      context.fillText(line, 160, 930 + index * 62);
    });

  context.fillStyle = "#d34235";
  context.font = "900 52px sans-serif";
  context.fillText("木鱼已敲，心态先稳住。", 160, 1160);

  context.fillStyle = "#75695f";
  context.font = "800 38px sans-serif";
  context.fillText(model.siteLine, 160, 1300);
}

function roundRect(context, x, y, width, height, radius) {
  context.beginPath();
  context.moveTo(x + radius, y);
  context.lineTo(x + width - radius, y);
  context.quadraticCurveTo(x + width, y, x + width, y + radius);
  context.lineTo(x + width, y + height - radius);
  context.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
  context.lineTo(x + radius, y + height);
  context.quadraticCurveTo(x, y + height, x, y + height - radius);
  context.lineTo(x, y + radius);
  context.quadraticCurveTo(x, y, x + radius, y);
  context.closePath();
}

