126	function roundRect(context, x, y, width, height, radius) {
127	  context.beginPath();
128	  context.moveTo(x + radius, y);
129	  context.lineTo(x + width - radius, y);
130	  context.quadraticCurveTo(x + width, y, x + width, y + radius);
131	  context.lineTo(x + width, y + height - radius);
132	  context.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
133	  context.lineTo(x + radius, y + height);
134	  context.quadraticCurveTo(x, y + height, x, y + height - radius);
135	  context.lineTo(x, y + radius);
136	  context.quadraticCurveTo(x, y, x + radius, y);
137	  context.closePath();
138	}
